{
  "executive_summary": "The system faces a capacity crisis within 2-3 months. At 20% month-over-month order growth, PostgreSQL will hit CPU saturation by month 2 and disk exhaustion by month 3. The P99 latency of 800ms and full table scans on order search will degrade to unacceptable levels well before that. The plan prescribes three phases: immediate triage (indexing, read replicas, disk expansion), medium-term restructuring (caching, query optimization, partitioning), and long-term architectural evolution (CQRS for read-heavy paths, archival strategy). All phases are scoped for a 4-engineer team.",

  "architecture": {
    "components": [
      { "name": "PostgreSQL Primary", "responsibility": "Transactional writes for orders, customers, deliveries. Source of truth.", "boundaries": "All writes go here. No heavy analytical or search queries should hit this node." },
      { "name": "PostgreSQL Read Replica(s)", "responsibility": "Serve read-heavy queries: order search by customer, delivery history aggregation, reporting.", "boundaries": "Eventually consistent (replication lag < 1s acceptable for these use cases). No writes." },
      { "name": "API Servers (x4 → x6)", "responsibility": "Handle HTTP requests, route reads vs writes, application-level caching.", "boundaries": "Stateless. Horizontal scaling. Read queries directed to replica(s)." },
      { "name": "Redis Cache Layer", "responsibility": "Cache hot-path reads: recent order lookups by customer, delivery status, aggregated delivery history.", "boundaries": "TTL-based invalidation. Not source of truth. Cache-aside pattern." },
      { "name": "Materialized Views / Projections", "responsibility": "Pre-computed delivery history aggregations, order search indexes.", "boundaries": "Refreshed on write via triggers or async events. Lives on read replica or dedicated store." },
      { "name": "Data Archival Service", "responsibility": "Move orders older than 12 months to cold storage (S3 + Athena or similar). Keep hot dataset small.", "boundaries": "Batch process. Runs during off-peak. Archived data queryable but not via primary DB." }
    ],
    "interfaces": [
      { "from": "API Servers", "to": "PostgreSQL Primary", "contract": "Write path: INSERT/UPDATE orders, deliveries. Connection pooling via PgBouncer.", "coupling_type": "synchronous" },
      { "from": "API Servers", "to": "PostgreSQL Read Replica", "contract": "Read path: SELECT queries for search, history, reporting. Routed at application or connection-pool level.", "coupling_type": "synchronous" },
      { "from": "API Servers", "to": "Redis Cache", "contract": "Cache-aside: check cache → miss → query replica → populate cache. TTL 60-300s depending on data type.", "coupling_type": "synchronous" },
      { "from": "PostgreSQL Primary", "to": "PostgreSQL Read Replica", "contract": "Streaming replication. Async. Sub-second lag.", "coupling_type": "asynchronous" },
      { "from": "Data Archival Service", "to": "PostgreSQL Primary", "contract": "Batch DELETE of archived rows during maintenance windows. Writes archive to cold storage.", "coupling_type": "asynchronous-batch" }
    ],
    "data_flow": "Writes → API → PgBouncer → PostgreSQL Primary → streaming replication → Read Replica. Reads → API → Redis (cache hit) OR → Read Replica (cache miss) → populate Redis. Aggregations served from materialized views on read replica, refreshed periodically. Archival service runs nightly, moves aged data to cold storage, reclaims disk on primary.",
    "patterns_used": [
      { "pattern": "Read Replica / Primary-Replica Split", "rationale": "Immediately offloads 60-70% of query load (reads) from the primary, buying CPU headroom. Simplest scaling lever for a 4-person team." },
      { "pattern": "Cache-Aside with Redis", "rationale": "Order-by-customer lookups are highly cacheable (same customer checks status repeatedly). Reduces replica load and slashes P99 latency." },
      { "pattern": "Table Partitioning (by date)", "rationale": "Orders table partitioned by created_at month. Enables efficient archival, faster queries on recent data, and partition-level maintenance." },
      { "pattern": "Materialized Views", "rationale": "Delivery history aggregation is expensive and changes slowly. Pre-compute and refresh on a schedule (every 5-15 min) rather than computing per-request." },
      { "pattern": "Connection Pooling (PgBouncer)", "rationale": "With growing API instances, connection count to PostgreSQL will become a bottleneck. PgBouncer in transaction mode keeps connections bounded." },
      { "pattern": "Data Archival / Cold-Hot Split", "rationale": "At 9x data growth over 12 months, keeping all historical data in PostgreSQL is unsustainable. Archive orders >12 months to cold storage." }
    ]
  },

  "domain_model": {
    "bounded_contexts": [
      { "name": "Order Management", "classification": "core", "aggregates": ["Order", "OrderLineItem"] },
      { "name": "Delivery Tracking", "classification": "core", "aggregates": ["Delivery", "DeliveryEvent"] },
      { "name": "Customer", "classification": "supporting", "aggregates": ["Customer", "CustomerProfile"] },
      { "name": "Reporting & Analytics", "classification": "supporting", "aggregates": ["OrderSummary", "DeliveryHistoryProjection"] }
    ],
    "context_map": [
      { "upstream": "Order Management", "downstream": "Delivery Tracking", "relationship": "Customer-Supplier: Order creates delivery; delivery references order ID but owns its own lifecycle." },
      { "upstream": "Order Management", "downstream": "Reporting & Analytics", "relationship": "Published Language: Orders emit events/state that reporting consumes to build projections." },
      { "upstream": "Delivery Tracking", "downstream": "Reporting & Analytics", "relationship": "Published Language: Delivery events feed aggregation projections." }
    ]
  },

  "trade_offs": [
    {
      "decision": "Read replica + cache instead of migrating to a distributed database (e.g., CockroachDB, Citus)",
      "gains": "Low operational complexity, team already knows PostgreSQL, achievable in weeks not months, no data migration risk",
      "sacrifices": "Eventually consistent reads (acceptable for this domain), will need revisiting at ~500K+ orders/day",
      "alternatives_considered": ["CockroachDB (distributed SQL — high migration cost, overkill at current scale)", "Citus (PostgreSQL sharding — good option at 500K+/day but premature now)", "Aurora PostgreSQL (managed, auto-scaling storage — viable if on AWS, vendor lock-in)"]
    },
    {
      "decision": "Date-based partitioning over customer-based sharding",
      "gains": "Simpler to implement, natural archival boundary, most queries filter by time range, no application-level routing logic",
      "sacrifices": "Customer-specific queries still need an index (B-tree on customer_id), hot partitions for current month",
      "alternatives_considered": ["Hash partitioning by customer_id (optimizes customer lookup but complicates time-range queries and archival)", "Application-level sharding (too complex for 4 engineers)"]
    },
    {
      "decision": "Materialized views over full CQRS with event sourcing",
      "gains": "Dramatically simpler, no new infrastructure, solves the delivery aggregation problem directly",
      "sacrifices": "Refresh lag (minutes), not real-time. Limited to queries that can be expressed as materialized views",
      "alternatives_considered": ["Full CQRS with event store (ideal at larger scale but massive investment for 4 engineers)", "Elasticsearch for search (adds operational burden of a new system)"]
    },
    {
      "decision": "Archive to cold storage at 12 months rather than keeping all data hot",
      "gains": "Keeps PostgreSQL dataset manageable (<1TB), improves vacuum performance, reduces backup times",
      "sacrifices": "Querying archived data requires a separate path (slower, different API), adds complexity for support queries spanning archive boundary",
      "alternatives_considered": ["Keep everything in PostgreSQL with larger disk (postpones problem 6 months at most)", "Move to data lake architecture (too large a shift for this team size)"]
    }
  ],

  "flexibility_points": [
    { "area": "Read replica count", "evolution_path": "Start with 1 replica, add more as read load grows. No application changes needed if using a connection pool with read/write splitting." },
    { "area": "Cache layer", "evolution_path": "Start with Redis cache-aside for top 2-3 hot queries. Expand cache coverage incrementally based on observed hit rates." },
    { "area": "Materialized views → CQRS", "evolution_path": "Materialized views are a stepping stone. If real-time projections become necessary, evolve to async event-driven projections without rewriting the write path." },
    { "area": "Archival boundary", "evolution_path": "Start archiving at 12 months. Adjust retention window based on actual query patterns and disk pressure." },
    { "area": "API server scaling", "evolution_path": "Stateless servers scale horizontally. Auto-scaling group based on CPU/request count. Current 4 → 6-8 over 12 months." }
  ],

  "rigidity_points": [
    { "area": "PostgreSQL as primary datastore", "reason": "Migrating away from PostgreSQL would be enormously expensive. All optimizations assume PostgreSQL. This is a deliberate bet — PostgreSQL can handle this scale with proper tuning." },
    { "area": "Orders table schema", "reason": "Partitioning requires a partitioning key in the primary key. This is a one-time schema migration that's hard to reverse. Choose the partition key carefully (created_at recommended)." },
    { "area": "Archive data format", "reason": "Once data is archived to cold storage in a specific format, changing that format requires re-processing all archived data. Design the archive schema carefully upfront." }
  ],

  "risks": [
    {
      "risk": "Disk exhaustion on PostgreSQL primary within 1-2 months. At 85% utilization (400GB of ~470GB), with 20% MoM data growth adding ~15-20GB/month of new order data, disk fills within 4-8 weeks.",
      "severity": "critical",
      "mitigation": "IMMEDIATE: Expand disk to 1TB (or enable auto-expanding storage if cloud-managed). Begin archival planning in parallel. This is a week-1 action."
    },
    {
      "risk": "CPU saturation on PostgreSQL primary within 2-3 months. At 70% peak CPU with 20% MoM growth, the primary hits sustained 100% CPU by month 2-3, causing cascading query timeouts.",
      "severity": "critical",
      "mitigation": "IMMEDIATE (week 1-2): Add indexes to eliminate full table scans on order search by customer. FAST FOLLOW (week 3-4): Deploy read replica and route read queries to it. These two actions alone should drop primary CPU to ~30-40%."
    },
    {
      "risk": "Full table scan on order-by-customer query degrades non-linearly as data grows. This query will go from slow to unusable within 3 months.",
      "severity": "critical",
      "mitigation": "Add composite index: CREATE INDEX idx_orders_customer_created ON orders(customer_id, created_at DESC). This is a day-1 fix. Expected to reduce that query from full scan to index lookup (<10ms)."
    },
    {
      "risk": "P99 latency (800ms) will breach SLAs as load increases. Under 2x load, P99 will likely exceed 2-3 seconds.",
      "severity": "high",
      "mitigation": "Indexing fixes the worst offenders. Redis caching handles repeat queries. Read replica prevents write-read contention. Target: P99 < 300ms within 6 weeks."
    },
    {
      "risk": "Connection pool exhaustion as API servers scale from 4 to 6-8 instances. Each instance likely holds 20-50 connections. PostgreSQL default max_connections=100.",
      "severity": "high",
      "mitigation": "Deploy PgBouncer in transaction pooling mode between API servers and PostgreSQL. Allows hundreds of application connections multiplexed over ~50 actual DB connections."
    },
    {
      "risk": "Team bandwidth — 4 engineers implementing scaling changes while shipping features. Risk of neither getting done well.",
      "severity": "high",
      "mitigation": "Phase the work strictly. Phase 1 (indexing + disk) requires <1 engineer-week. Phase 2 (replica + cache) requires ~2-3 engineer-weeks. Dedicate 1-2 engineers to scaling for 6 weeks, others continue feature work."
    },
    {
      "risk": "Replication lag under heavy write load could cause stale reads on replica.",
      "severity": "medium",
      "mitigation": "Monitor replication lag. For the identified read queries (order search, delivery history), sub-second staleness is acceptable. For any read-after-write scenarios, route to primary."
    },
    {
      "risk": "Vacuum bloat on large orders table slows autovacuum, causing transaction ID wraparound risk.",
      "severity": "medium",
      "mitigation": "Partitioning by date allows dropping old partitions cleanly (no vacuum needed). Tune autovacuum for large tables: increase autovacuum_vacuum_scale_factor, autovacuum_work_mem."
    }
  ],

  "implementation_guidance": {
    "recommended_approach": "Three phases over 12 months. Phase 1 (Weeks 1-2, EMERGENCY): Add missing indexes, expand disk to 1TB+, deploy PgBouncer. Phase 2 (Weeks 3-8): Deploy read replica, implement read/write split in application, add Redis caching for order-by-customer and delivery status queries, create materialized views for delivery history aggregation. Phase 3 (Months 3-12): Implement date-based table partitioning on orders table, build and deploy data archival service, add 2 more API server instances, implement monitoring dashboards for all new components. Each phase has clear success metrics and can be executed by 1-2 engineers.",
    "files_to_create_or_modify": [
      "migrations/001_add_order_customer_index.sql — CREATE INDEX CONCURRENTLY idx_orders_customer_created ON orders(customer_id, created_at DESC)",
      "migrations/002_add_delivery_aggregation_matview.sql — Materialized view for delivery history aggregation",
      "migrations/003_partition_orders_by_month.sql — Convert orders table to range-partitioned by created_at",
      "config/pgbouncer.ini — PgBouncer configuration: transaction pooling mode, pool_size=50",
      "config/database.yml (or equivalent) — Add read_replica connection configuration",
      "src/db/connection.ts (or equivalent) — Read/write splitting logic: writes → primary, reads → replica",
      "src/cache/redis.ts — Cache-aside wrapper for Redis with TTL configuration per query type",
      "src/services/order-search.ts — Refactor to use cache + read replica for customer order lookups",
      "src/services/delivery-history.ts — Refactor to query materialized view on read replica",
      "src/jobs/archival.ts — Nightly job: archive orders > 12 months to cold storage, drop old partitions",
      "infrastructure/monitoring/dashboards/ — Grafana dashboards for replication lag, cache hit rate, query latency percentiles, disk usage"
    ],
    "patterns_to_follow": "Cache-aside for Redis (never write-through — too complex for this stage). Read/write split at the application connection level (not query-level routing). Materialized views refreshed via pg_cron or application-level scheduler every 5-15 minutes. Index creation always uses CONCURRENTLY to avoid table locks. Partitioning migration uses pg_partman for automated partition management.",
    "pitfalls_to_avoid": [
      "Do NOT add indexes without CONCURRENTLY — a regular CREATE INDEX on a 400GB table will lock writes for minutes to hours",
      "Do NOT implement application-level sharding — it's premature and too complex for a 4-person team at this scale",
      "Do NOT cache writes or use write-through caching — cache invalidation bugs will cause data inconsistency",
      "Do NOT skip PgBouncer — direct connections from 6+ API servers will exhaust PostgreSQL connection limits under load",
      "Do NOT partition before adding indexes — indexing is a day-1 fix; partitioning is a month-2 project with higher risk",
      "Do NOT attempt to optimize both slow queries simultaneously — fix order-by-customer index first (biggest impact), then tackle delivery aggregation with materialized views",
      "Do NOT run archival during peak hours — batch deletes cause vacuum pressure and replication lag spikes"
    ]
  },

  "escalations": [],

  "confidence": {
    "level": 78,
    "high_confidence_areas": [
      "Missing index on customer_id is almost certainly the root cause of the full table scan — this is a day-1 fix with predictable impact",
      "Read replica will meaningfully reduce primary CPU load — this is a well-understood PostgreSQL scaling pattern",
      "Disk will be exhausted within 1-2 months — the math is unambiguous at 85% utilization with 20% MoM growth",
      "PgBouncer is the correct connection pooling solution for PostgreSQL at this scale"
    ],
    "low_confidence_areas": [
      "Exact growth rate of disk usage — 20% MoM order growth doesn't map linearly to disk growth (depends on row size, indexes, bloat). Actual timeline to disk exhaustion could be 4-12 weeks.",
      "Whether delivery history aggregation is best served by materialized views or requires a dedicated OLAP solution — depends on query complexity not visible in the problem statement",
      "Cache hit rates for order-by-customer queries — depends on access patterns (repeat customers vs. one-time). Need to instrument before committing to cache sizing.",
      "Whether the 4-engineer team has PostgreSQL operational expertise for replication, partitioning, and PgBouncer setup — if not, managed database services (RDS/Cloud SQL) reduce risk significantly"
    ],
    "assumptions": [
      "20% MoM growth rate is sustained for 12 months (compounds to ~9x). If growth decelerates, the timeline extends but the plan remains valid.",
      "The workload is read-heavy (typical for order management systems — many status checks per order). If write-heavy, the replica strategy provides less relief.",
      "PostgreSQL is self-managed. If using a managed service (RDS, Cloud SQL), some steps simplify (auto-expanding storage, managed replicas).",
      "The 150ms average / 800ms P99 query times are dominated by the two identified slow queries. If latency is spread across many query types, the indexing fix provides less improvement.",
      "No significant schema changes are planned that would conflict with partitioning or indexing."
    ]
  }
}
